const sortIdList = (value) =>
  [...(Array.isArray(value) ? value : [])]
    .map((id) => Number(id))
    .filter((n) => !Number.isNaN(n))
    .sort((a, b) => a - b);

export const autoAssignFieldValueMatchesRule = (fieldName, currentValue, ruleValue) => {
  if (fieldName === 'userIds' || fieldName === 'observerUserIds') {
    return _.isEqual(sortIdList(currentValue), sortIdList(ruleValue));
  }
  if (isAutoAssignValueEmpty(ruleValue)) {
    return false;
  }
  return Number(currentValue) === Number(ruleValue);
};

/**
 * For edit mode: infer which Regarding fields match the auto-assignment rule for the current Type+Category
 * so clear/change Type or Category can clear persisted auto-filled values.
 */
export const computeAutoOwnedFieldsFromRule = (rule, currentValues) => {
  const owned = new Set();
  if (!rule) {
    return owned;
  }
  const picked = _.pick(currentValues, AUTO_ASSIGNMENT_FIELDS);
  AUTO_ASSIGNMENT_FIELDS.forEach((fieldName) => {
    const ruleVal = rule[fieldName];
    if (isAutoAssignValueEmpty(ruleVal)) {
      return;
    }
    const cur = picked[fieldName];
    if (autoAssignFieldValueMatchesRule(fieldName, cur, ruleVal)) {
      owned.add(fieldName);
    }
  });
  return owned;
};

