/** Stable-ish key for when to re-seed autoOwned on edit (server snapshot + settings identity). */
export const getJrDetailAutoAssignFingerprint = (detail) => {
  if (!detail?.id) {
    return '';
  }
  const pic = _.map(detail.users || [], (u) => u?.id)
    .filter(Boolean)
    .sort((a, b) => a - b)
    .join(',');
  const obs = _.map(detail.observerUsers || [], (u) => u?.id)
    .filter(Boolean)
    .sort((a, b) => a - b)
    .join(',');
  return [detail.id, detail.categoryId, detail.subCategoryId, detail.priorityId, detail.teamId, pic, obs].join('|');
};

