input.contents:
import React from 'react';
import _ from 'lodash';

/**
 * Type+Category → rule (priority, team, PIC, observers from `normalWorkOrderSettings`).
 * autoOwned = which fields the rule last set; user edit drops that field and flips “touched” so we don’t
 * re-apply the rule for the same pair (untouched fields stay autoOwned for later clears). Create: default
 * priority can yield to the rule until changed. Edit: seed autoOwned from loaded JR vs rule; re-seed only
 * when `buildAutoAssignEditSeedKey` changes. No rule → clear auto-owned only; category cleared → all four + reset.
 */
export const AUTO_ASSIGNMENT_FIELDS = ['priorityId', 'teamId', 'userIds', 'observerUserIds'];

export const getAutoAssignFieldEmptyValue = (fieldName) => {
  if (fieldName === 'userIds' || fieldName === 'observerUserIds') {
    return [];
  }
  return undefined;
};

export const isAutoAssignValueEmpty = (value) => {
  if (Array.isArray(value)) {
    return value.length === 0;
  }
  return _.isNil(value);
};

export const normalizeAutoAssignmentRule = (rule) => ({
  priorityId: rule?.priorityId || rule?.priority?.id,
  teamId: rule?.teamId || rule?.team?.id,
  userIds: _.map(rule?.users || rule?.userIds || [], (item) => item?.id || item?.userId || item).filter(Boolean),
  observerUserIds: _.map(rule?.observerUsers || rule?.observerUserIds || [], (item) => item?.id || item?.userId || item).filter(
    Boolean
  ),
});

export const getAutoAssignmentRuleByTypeAndCategory = (settings, typeId, categoryId) => {
  if (!typeId || !categoryId) {
    return null;
  }
  const categorySetting = _.find(settings, (item) => item?.categoryId === typeId);
  const categoryRule = _.find(categorySetting?.settings, (item) => item?.subCategoryId === categoryId);
  return categoryRule ? normalizeAutoAssignmentRule(categoryRule) : null;
};

const sortIdList = (value) =>
  [...(Array.isArray(value) ? value : [])]
    .map((id) => Number(id))
    .filter((n) => !Number.isNaN(n))
    .sort((a, b) => a - b);

export const autoAssignFieldValueMatchesRule = (fieldName, currentValue, ruleValue) => {
  if (fieldName === 'userIds' || fieldName === 'observerUserIds') {
    return _.isEqual(sortIdList(currentValue), sortIdList(ruleValue));
  }
  if (isAutoAssignValueEmpty(ruleValue)) {
    return false;
  }
  return Number(currentValue) === Number(ruleValue);
};

/** Edit seed: fields whose current values match the rule → treat as auto-owned. */
export const computeAutoOwnedFieldsFromRule = (rule, currentValues) => {
  const owned = new Set();
  if (!rule) {
    return owned;
  }
  const picked = _.pick(currentValues, AUTO_ASSIGNMENT_FIELDS);
  AUTO_ASSIGNMENT_FIELDS.forEach((fieldName) => {
    const ruleVal = rule[fieldName];
    if (isAutoAssignValueEmpty(ruleVal)) {
      return;
    }
    const cur = picked[fieldName];
    if (autoAssignFieldValueMatchesRule(fieldName, cur, ruleVal)) {
      owned.add(fieldName);
    }
  });
  return owned;
};

/** Edit: when this string changes, re-run seed (detail snapshot). */
export const buildAutoAssignEditSeedKey = (detail) => {
  if (!detail?.id) {
    return '';
  }
  const pic = _.map(detail.users || [], (u) => u?.id)
    .filter(Boolean)
    .sort((a, b) => a - b)
    .join(',');
  const obs = _.map(detail.observerUsers || [], (u) => u?.id)
    .filter(Boolean)
    .sort((a, b) => a - b)
    .join(',');
  return [detail.id, detail.categoryId, detail.subCategoryId, detail.priorityId, detail.teamId, pic, obs].join('|');
};

/** Pure merge: apply rule to the four fields + next autoOwned set (hook + tests). */
export const applyAutoAssignmentValues = ({
  currentValues,
  autoOwnedFields,
  rule,
  allowAppDefaultPriorityOverride = false,
  skipRegardingAutoAssignment = false,
} = {}) => {
  const nextValues = { ...currentValues };
  const nextAutoOwned = new Set(autoOwnedFields || []);

  if (!rule) {
    AUTO_ASSIGNMENT_FIELDS.forEach((fieldName) => {
      if (nextAutoOwned.has(fieldName)) {
        nextValues[fieldName] = getAutoAssignFieldEmptyValue(fieldName);
        nextAutoOwned.delete(fieldName);
      }
    });
    return { nextValues, nextAutoOwned };
  }

  // Do not strip autoOwned here: user may later clear category only; clearCurrentAutoFilledValues
  // must still clear fields that stayed auto-filled (manual fields already removed from autoOwned).
  if (skipRegardingAutoAssignment) {
    return { nextValues, nextAutoOwned };
  }

  AUTO_ASSIGNMENT_FIELDS.forEach((fieldName) => {
    const nextRuleValue = rule[fieldName];
    const isAutoOwned = nextAutoOwned.has(fieldName);
    const currentValue = currentValues[fieldName];
    const priorityEligibleForRuleOverAppDefault =
      fieldName === 'priorityId' && allowAppDefaultPriorityOverride;
    const canOverride = isAutoOwned || isAutoAssignValueEmpty(currentValue) || priorityEligibleForRuleOverAppDefault;

    if (isAutoAssignValueEmpty(nextRuleValue)) {
      if (isAutoOwned) {
        nextValues[fieldName] = getAutoAssignFieldEmptyValue(fieldName);
        nextAutoOwned.delete(fieldName);
      }
      return;
    }

    if (canOverride) {
      nextValues[fieldName] = nextRuleValue;
      nextAutoOwned.add(fieldName);
    }
  });

  return { nextValues, nextAutoOwned };
};

/** Args: `normalWorkOrderSettings`, optional create `defaultPriorityId`. Returns apply / manual / clear / seed / reset. */
const useJobRequestAutoAssignment = ({ normalWorkOrderSettings = [], defaultPriorityId } = {}) => {
  const autoOwnedFieldsRef = React.useRef(new Set());
  const isApplyingAutoAssignRef = React.useRef(false);
  /** Manual Regarding edit → skip rule re-apply until Type/Category changes (AddOrEdit resets on clear/type). */
  const regardingFieldsUserTouchedRef = React.useRef(false);
  /** Edit seed idempotency: skip until JR snapshot or settings reference changes (see `useEditAutoOwnedSeedFromLoadedJr`). */
  const editSeedGuardRef = React.useRef({ jrSnapshotKey: null, settingsRef: null });

  const resetRegardingSessionRefs = React.useCallback(() => {
    autoOwnedFieldsRef.current = new Set();
    regardingFieldsUserTouchedRef.current = false;
    editSeedGuardRef.current = { jrSnapshotKey: null, settingsRef: null };
  }, []);

  const resetAutoOwnedFields = resetRegardingSessionRefs;

  const markAutoAssignFieldAsManual = React.useCallback((fieldName) => {
    if (isApplyingAutoAssignRef.current) {
      return;
    }
    autoOwnedFieldsRef.current.delete(fieldName);
    if (AUTO_ASSIGNMENT_FIELDS.includes(fieldName)) {
      regardingFieldsUserTouchedRef.current = true;
    }
  }, []);

  const applyRuntimeAutoAssignment = React.useCallback(({ rule, currentValues, setFieldValue, getUserInTeam }) => {
    const picked = _.pick(currentValues, AUTO_ASSIGNMENT_FIELDS);
    const skipRegardingAutoAssignment = regardingFieldsUserTouchedRef.current;
    const allowAppDefaultPriorityOverride =
      !skipRegardingAutoAssignment &&
      defaultPriorityId != null &&
      !_.isNil(picked.priorityId) &&
      Number(picked.priorityId) === Number(defaultPriorityId);

    const { nextValues, nextAutoOwned } = applyAutoAssignmentValues({
      currentValues: picked,
      autoOwnedFields: autoOwnedFieldsRef.current,
      rule,
      allowAppDefaultPriorityOverride,
      skipRegardingAutoAssignment,
    });

    isApplyingAutoAssignRef.current = true;
    AUTO_ASSIGNMENT_FIELDS.forEach((fieldName) => {
      if (!_.isEqual(currentValues[fieldName], nextValues[fieldName])) {
        setFieldValue(fieldName, nextValues[fieldName]);
      }
    });
    isApplyingAutoAssignRef.current = false;

    if (!_.isEqual(currentValues.teamId, nextValues.teamId) && !isAutoAssignValueEmpty(nextValues.teamId) && getUserInTeam) {
      getUserInTeam(nextValues.teamId);
    }

    autoOwnedFieldsRef.current = nextAutoOwned;
  }, [defaultPriorityId]);

  const clearCurrentAutoFilledValues = React.useCallback(
    ({ currentValues, setFieldValue }) => {
      applyRuntimeAutoAssignment({
        rule: null,
        currentValues,
        setFieldValue,
      });
    },
    [applyRuntimeAutoAssignment]
  );

  /** Category cleared: blank all four Regarding fields + session refs. */
  const clearAllRegardingAssignmentFields = React.useCallback(
    ({ setFieldValue }) => {
      isApplyingAutoAssignRef.current = true;
      AUTO_ASSIGNMENT_FIELDS.forEach((fieldName) => {
        setFieldValue(fieldName, getAutoAssignFieldEmptyValue(fieldName));
      });
      isApplyingAutoAssignRef.current = false;
      resetRegardingSessionRefs();
    },
    [resetRegardingSessionRefs]
  );

  const applyAutoAssignmentByTypeAndCategory = React.useCallback(
    ({ typeId, categoryId, currentValues, setFieldValue, getUserInTeam }) => {
      const selectedRule = getAutoAssignmentRuleByTypeAndCategory(normalWorkOrderSettings, typeId, categoryId);
      applyRuntimeAutoAssignment({
        rule: selectedRule,
        currentValues,
        setFieldValue,
        getUserInTeam,
      });
    },
    [normalWorkOrderSettings, applyRuntimeAutoAssignment]
  );

  const seedAutoOwnedFromLoadedJr = React.useCallback(
    ({ typeId, categoryId, currentValues }) => {
      const rule = getAutoAssignmentRuleByTypeAndCategory(normalWorkOrderSettings, typeId, categoryId);
      autoOwnedFieldsRef.current = computeAutoOwnedFieldsFromRule(rule, currentValues);
    },
    [normalWorkOrderSettings]
  );

  return {
    resetAutoOwnedFields,
    markAutoAssignFieldAsManual,
    clearCurrentAutoFilledValues,
    clearAllRegardingAssignmentFields,
    applyAutoAssignmentByTypeAndCategory,
    seedAutoOwnedFromLoadedJr,
    editSeedGuardRef,
  };
};

/**
 * Call after `useForm` provides `getValues`. Seeds edit `autoOwned` when JR detail + rules are ready,
 * without thrashing on repeated `jrDetail` object identity or before `normalWorkOrderSettings` arrives.
 * Init does not require any UI touch: we infer auto-owned by matching form values to the rule (see `computeAutoOwnedFieldsFromRule`).
 */
export const useEditAutoOwnedSeedFromLoadedJr = ({
